const e=JSON.parse(`[{"id":1,"section":"A","theme":"Daily activities","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne court dans le parc","image_prompt":"A person running in a green park, sunny day"},{"id":"B","text":"Une personne fait du vélo","image_prompt":"A person riding a bicycle on a city path"},{"id":"C","text":"Une personne nage","image_prompt":"A person swimming in a blue pool"},{"id":"D","text":"Une personne marche avec un chien","image_prompt":"A person walking a golden retriever in a park"}],"correct":0,"transcript_fr":"J'adore commencer ma journée par un petit footing au parc quand il fait beau.","transcript_en":"I love starting my day with a quick jog in the park when the weather is nice.","points":[{"point":1,"male_lines":["J'adore commencer ma journée par un petit footing au parc quand il fait beau.","C'est vraiment agréable de respirer l'air frais le matin."],"female_lines":[]}]},{"id":2,"section":"A","theme":"Transportation","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un autobus scolaire","image_prompt":"A yellow school bus on a street"},{"id":"B","text":"Un métro souterrain","image_prompt":"A subway train arriving at a station"},{"id":"C","text":"Un taxi","image_prompt":"A yellow taxi cab on a city street"},{"id":"D","text":"Un train interurbain","image_prompt":"A commuter train on railway tracks"}],"correct":1,"transcript_fr":"Je prends toujours le métro pour aller travailler, c'est plus rapide que l'autobus.","transcript_en":"I always take the subway to go to work, it's faster than the bus.","points":[{"point":1,"male_lines":["Je prends toujours le métro pour aller travailler, c'est plus rapide que l'autobus.","La ligne orange est directe jusqu'à mon bureau au centre-ville."],"female_lines":[]}]},{"id":3,"section":"A","theme":"Food and dining","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une pâtisserie avec des croissants","image_prompt":"A bakery display with croissants and pastries"},{"id":"B","text":"Un restaurant de sushi","image_prompt":"A sushi restaurant with a chef preparing rolls"},{"id":"C","text":"Une pizzeria","image_prompt":"A pizza oven with pizzas being baked"},{"id":"D","text":"Un café servant des sandwichs","image_prompt":"A coffee shop serving sandwiches and lattes"}],"correct":2,"transcript_fr":"Ce soir, j'ai vraiment envie de manger une bonne pizza avec des amis.","transcript_en":"Tonight, I really feel like eating a good pizza with friends.","points":[{"point":1,"male_lines":["Ce soir, j'ai vraiment envie de manger une bonne pizza avec des amis.","Il y a une nouvelle pizzeria italienne qui vient d'ouvrir sur la rue Saint-Denis."],"female_lines":[]}]},{"id":4,"section":"A","theme":"Weather","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une journée ensoleillée à la plage","image_prompt":"A sunny beach scene with people swimming"},{"id":"B","text":"Une tempête de neige","image_prompt":"A heavy snowstorm with snow-covered streets"},{"id":"C","text":"Une journée pluvieuse avec un parapluie","image_prompt":"A person holding an umbrella in the rain"},{"id":"D","text":"Un ciel nuageux mais sans pluie","image_prompt":"A cloudy sky over a city park"}],"correct":3,"transcript_fr":"N'oublie pas ton parapluie, il pleut des cordes dehors!","transcript_en":"Don't forget your umbrella, it's pouring rain outside!","points":[{"point":1,"male_lines":["N'oublie pas ton parapluie, il pleut des cordes dehors!","La météo annonce des averses toute la journée."],"female_lines":[]}]},{"id":5,"section":"A","theme":"Shopping","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un supermarché avec des caddies","image_prompt":"A supermarket interior with shopping carts"},{"id":"B","text":"Une pharmacie","image_prompt":"A pharmacy counter with medications"},{"id":"C","text":"Un magasin de vêtements","image_prompt":"A clothing store with racks of clothes"},{"id":"D","text":"Une librairie","image_prompt":"A bookstore with shelves of books"}],"correct":0,"transcript_fr":"Je dois passer à l'épicerie acheter du lait et du pain pour demain matin.","transcript_en":"I need to stop by the grocery store to buy milk and bread for tomorrow morning.","points":[{"point":1,"male_lines":["Je dois passer à l'épicerie acheter du lait et du pain pour demain matin.","Le supermarché ferme dans une heure, je dois me dépêcher."],"female_lines":[]}]},{"id":6,"section":"A","theme":"Work","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un bureau avec un ordinateur portable","image_prompt":"A modern office desk with a laptop"},{"id":"B","text":"Une réunion en visioconférence","image_prompt":"A video conference meeting on a screen"},{"id":"C","text":"Un chantier de construction","image_prompt":"A construction site with workers and equipment"},{"id":"D","text":"Une salle de classe","image_prompt":"A classroom with students and a teacher"}],"correct":1,"transcript_fr":"On se retrouve sur Zoom à quatorze heures pour la réunion d'équipe.","transcript_en":"Let's meet on Zoom at two o'clock for the team meeting.","points":[{"point":1,"male_lines":["On se retrouve sur Zoom à quatorze heures pour la réunion d'équipe.","N'oubliez pas d'activer vos caméras pour cette présentation."],"female_lines":[]}]},{"id":7,"section":"B","theme":"Making plans","question":"Que décident les interlocuteurs de faire ?","options":[{"id":"A","text":"Aller au cinéma ce soir","image_prompt":null},{"id":"B","text":"Dîner au restaurant samedi","image_prompt":null},{"id":"C","text":"Faire une randonnée dimanche","image_prompt":null},{"id":"D","text":"Visiter un musée","image_prompt":null}],"correct":1,"transcript_fr":"Homme: Tu es libre samedi soir? On pourrait aller manger quelque part. Femme: Bonne idée! Tu as un endroit en tête? Homme: Il y a ce nouveau restaurant grec sur l'avenue du Parc. Femme: Parfait, j'adore la cuisine méditerranéenne. Réservons une table pour deux.","transcript_en":"Man: Are you free Saturday night? We could go eat somewhere. Woman: Good idea! Do you have a place in mind? Man: There's this new Greek restaurant on Park Avenue. Woman: Perfect, I love Mediterranean cuisine. Let's book a table for two.","points":[{"point":1,"male_lines":["Tu es libre samedi soir?","On pourrait aller manger quelque part."],"female_lines":["Bonne idée!","Tu as un endroit en tête?"]},{"point":2,"male_lines":["Il y a ce nouveau restaurant grec sur l'avenue du Parc.","J'ai entendu dire que leur moussaka est excellente."],"female_lines":["Parfait, j'adore la cuisine méditerranéenne.","Réservons une table pour deux."]},{"point":3,"male_lines":["Je vais appeler maintenant pour voir s'ils ont de la place.","Quelle heure te conviendrait?"],"female_lines":["Vers dix-neuf heures, ça te va?","Oui, c'est parfait pour moi."]},{"point":4,"male_lines":["C'est noté, je fais la réservation tout de suite.","À samedi alors!"],"female_lines":["À samedi! J'ai hâte d'y être.","Merci pour l'invitation."]}]},{"id":8,"section":"B","theme":"Asking for directions","question":"Où veut aller l'homme ?","options":[{"id":"A","text":"À la banque","image_prompt":null},{"id":"B","text":"À la poste","image_prompt":null},{"id":"C","text":"À la bibliothèque","image_prompt":null},{"id":"D","text":"Au centre commercial","image_prompt":null}],"correct":2,"transcript_fr":"Homme: Excusez-moi madame, je cherche la bibliothèque municipale. Femme: C'est tout droit sur cette rue, puis à gauche après le feu rouge. Homme: C'est loin à pied? Femme: Non, environ cinq minutes. Vous verrez le grand bâtiment blanc avec des colonnes.","transcript_en":"Man: Excuse me ma'am, I'm looking for the municipal library. Woman: It's straight ahead on this street, then left after the traffic light. Man: Is it far to walk? Woman: No, about five minutes. You'll see the large white building with columns.","points":[{"point":1,"male_lines":["Excusez-moi madame, je cherche la bibliothèque municipale.","Je suis nouveau dans le quartier."],"female_lines":["Ah oui, c'est facile à trouver.","Je peux vous indiquer le chemin."]},{"point":2,"male_lines":["Merci beaucoup, c'est gentil.","Je dois rendre des livres avant ce soir."],"female_lines":["C'est tout droit sur cette rue, puis à gauche après le feu rouge.","Vous ne pouvez pas la manquer."]},{"point":3,"male_lines":["C'est loin à pied?","Je préfère marcher quand il fait beau."],"female_lines":["Non, environ cinq minutes.","C'est une petite balade agréable."]},{"point":4,"male_lines":["Parfait, je vais y aller maintenant.","Merci encore pour votre aide."],"female_lines":["Vous verrez le grand bâtiment blanc avec des colonnes.","Bonne journée à vous!"]}]},{"id":9,"section":"B","theme":"Shopping for clothes","question":"Quelle taille la femme cherche-t-elle ?","options":[{"id":"A","text":"La taille petite","image_prompt":null},{"id":"B","text":"La taille moyenne","image_prompt":null},{"id":"C","text":"La taille grande","image_prompt":null},{"id":"D","text":"La taille extra-grande","image_prompt":null}],"correct":2,"transcript_fr":"Femme: Bonjour, puis-je essayer cette robe en bleu? Homme: Bien sûr, quelle taille faites-vous? Femme: Je prends normalement du grand. Homme: Voilà, les cabines sont par là. Femme: Merci, je reviens tout de suite.","transcript_en":"Woman: Hello, may I try on this dress in blue? Man: Of course, what size do you wear? Woman: I usually take a large. Man: Here you go, the fitting rooms are over there. Woman: Thank you, I'll be right back.","points":[{"point":1,"male_lines":["Bonjour madame, je peux vous aider?","Vous cherchez quelque chose en particulier?"],"female_lines":["Bonjour, puis-je essayer cette robe en bleu?","Elle est vraiment jolie."]},{"point":2,"male_lines":["Bien sûr, quelle taille faites-vous?","Nous avons plusieurs coloris disponibles."],"female_lines":["Je prends normalement du grand.","Le bleu marine est ma couleur préférée."]},{"point":3,"male_lines":["Voilà, les cabines sont par là.","N'hésitez pas à appeler si vous avez besoin d'une autre taille."],"female_lines":["Merci, je reviens tout de suite.","J'espère qu'elle me ira bien."]},{"point":4,"male_lines":["Prenez votre temps.","Je serai ici si vous avez des questions."],"female_lines":["C'est parfait, merci beaucoup.","La qualité semble excellente."]}]},{"id":10,"section":"B","theme":"Doctor's appointment","question":"Quand est le rendez-vous fixé ?","options":[{"id":"A","text":"Demain matin","image_prompt":null},{"id":"B","text":"Demain après-midi","image_prompt":null},{"id":"C","text":"Après-demain","image_prompt":null},{"id":"D","text":"La semaine prochaine","image_prompt":null}],"correct":1,"transcript_fr":"Femme: Allô, je voudrais prendre rendez-vous avec le docteur Tremblay. Homme: Demain après-midi à quinze heures, ça vous convient? Femme: Oui, parfait. Homme: Très bien, votre nom s'il vous plaît? Femme: C'est Marie Lacroix.","transcript_en":"Woman: Hello, I would like to make an appointment with Dr. Tremblay. Man: Tomorrow afternoon at three o'clock, does that work for you? Woman: Yes, perfect. Man: Very well, your name please? Woman: It's Marie Lacroix.","points":[{"point":1,"male_lines":["Cabinet du docteur Tremblay, bonjour.","Comment puis-je vous aider?"],"female_lines":["Allô, je voudrais prendre rendez-vous avec le docteur Tremblay.","C'est pour un renouvellement d'ordonnance."]},{"point":2,"male_lines":["Demain après-midi à quinze heures, ça vous convient?","Nous avons aussi un créneau à seize heures trente."],"female_lines":["Oui, parfait, quinze heures me va très bien.","Merci beaucoup."]},{"point":3,"male_lines":["Très bien, votre nom s'il vous plaît?","Et votre date de naissance?"],"female_lines":["C'est Marie Lacroix.","Je suis née le 12 mars 1985."]},{"point":4,"male_lines":["C'est noté, Madame Lacroix.","Veuillez arriver dix minutes en avance."],"female_lines":["D'accord, je serai ponctuelle.","Au revoir et merci."]}]},{"id":11,"section":"C","theme":"Airport announcement","question":"Quel est le principal sujet de cette annonce ?","options":[{"id":"A","text":"Un retard de vol","image_prompt":null},{"id":"B","text":"Un changement de porte d'embarquement","image_prompt":null},{"id":"C","text":"Une annulation de vol","image_prompt":null},{"id":"D","text":"Un appel aux passagers manquants","image_prompt":null}],"correct":3,"transcript_fr":"Mesdames et messieurs, nous sollicitons votre attention pour un appel final concernant le vol Air Canada trois-quatre-sept à destination de Vancouver. Les passengers Jean Tremblay et Sophie Gagnon, priés de se présenter immédiatement à la porte vingt-quatre. Le décollage est imminent. Nous répétons, vol trois-quatre-sept, porte vingt-quatre, embarquement final. Merci.","transcript_en":"Ladies and gentlemen, we request your attention for a final call regarding Air Canada flight three-four-seven to Vancouver. Passengers Jean Tremblay and Sophie Gagnon, please proceed immediately to gate twenty-four. Departure is imminent. We repeat, flight three-four-seven, gate twenty-four, final boarding. Thank you.","points":[{"point":1,"male_lines":["Mesdames et messieurs, nous sollicitons votre attention pour un appel final.","Il s'agit du vol Air Canada trois-quatre-sept à destination de Vancouver."],"female_lines":[]},{"point":2,"male_lines":["Les passagers Jean Tremblay et Sophie Gagnon sont demandés à l'embarquement.","Ils doivent se présenter immédiatement à la porte vingt-quatre."],"female_lines":[]},{"point":3,"male_lines":["Le décollage est imminent, nous ne pouvons plus attendre.","C'est le dernier appel pour ces passagers."],"female_lines":[]},{"point":4,"male_lines":["Nous répétons, vol trois-quatre-sept, porte vingt-quatre, embarquement final.","Tous les autres passagers sont priés de rester à leur porte d'embarquement."],"female_lines":[]},{"point":5,"male_lines":["Merci de votre attention et bon voyage à tous.","Air Canada vous souhaite un agréable vol vers Vancouver."],"female_lines":[]},{"point":6,"male_lines":["Nous vous rappelons que le port du masque est obligatoire à bord.","Les consignes de sécurité seront présentées par notre équipage."],"female_lines":[]},{"point":7,"male_lines":["Pour toute question, veuillez contacter le comptoir d'Air Canada.","Notre personnel est à votre disposition."],"female_lines":[]},{"point":8,"male_lines":["Nous vous prions de bien vouloir vérifier votre carte d'embarquement.","Assurez-vous d'être à la bonne porte."],"female_lines":[]},{"point":9,"male_lines":["Le vol est plein, nous ne pourrons pas accepter de bagages supplémentaires en soute.","Veuillez respect les dimensions de bagages à main autorisées."],"female_lines":[]},{"point":10,"male_lines":["Encore une fois, dernier appel pour Jean Tremblay et Sophie Gagnon.","Porte vingt-quatre, immédiatement. Merci."],"female_lines":[]}]},{"id":12,"section":"C","theme":"Supermarket announcement","question":"Quelle promotion est annoncée ?","options":[{"id":"A","text":"50% de rabais sur les fruits","image_prompt":null},{"id":"B","text":"Deux pour le prix d'un sur le fromage","image_prompt":null},{"id":"C","text":"Un tiers de réduction sur la viande","image_prompt":null},{"id":"D","text":"Achat un, gratuit sur les légumes","image_prompt":null}],"correct":1,"transcript_fr":"Chers clients, profitez de notre offre spéciale aujourd'hui uniquement sur tous les fromages du Québec. Achetez-en deux et payez-en un seul. Cette promotion est valable jusqu'à la fermeture du magasin ce soir. Rendez-vous au rayon produits laitiers. Merci de votre fidélité.","transcript_en":"Dear customers, take advantage of our special offer today only on all Quebec cheeses. Buy two and pay for only one. This promotion is valid until the store closes tonight. Head to the dairy section. Thank you for your loyalty.","points":[{"point":1,"male_lines":["Chers clients, bienvenue dans votre supermarché Metro.","Nous avons une annonce spéciale pour vous aujourd'hui."],"female_lines":[]},{"point":2,"male_lines":["Profitez de notre offre spéciale aujourd'hui uniquement.","Elle concerne tous les fromages du Québec."],"female_lines":[]},{"point":3,"male_lines":["C'est simple, achetez-en deux et payez-en un seul.","C'est une économie de cinquante pourcent."],"female_lines":[]},{"point":4,"male_lines":["Cette promotion est valable jusqu'à la fermeture du magasin ce soir.","Ne manquez pas cette occasion exceptionnelle."],"female_lines":[]},{"point":5,"male_lines":["Rendez-vous au rayon produits laitiers, à votre droite en entrant.","Notre fromager sera ravi de vous conseiller."],"female_lines":[]},{"point":6,"male_lines":["Nous avons également des dégustations gratuites en ce moment.","Venez goûter notre nouveau cheddar vieilli de dix ans."],"female_lines":[]},{"point":7,"male_lines":["Merci de votre fidélité et bonne journée à tous.","N'oubliez pas votre carte de fidélité pour cumuler des points."],"female_lines":[]},{"point":8,"male_lines":["Prochainement, notre foire aux vins du Québec.","Des rabais exceptionnels sur les produits locaux."],"female_lines":[]},{"point":9,"male_lines":["Le stationnement est gratuit pour les deux premières heures.","Pensez à valider votre ticket à la caisse."],"female_lines":[]},{"point":10,"male_lines":["Encore une fois, fromages du Québec, deux pour un.","À bientôt dans votre magasin Metro."],"female_lines":[]}]},{"id":13,"section":"C","theme":"Train station announcement","question":"Quel problème est mentionné dans l'annonce ?","options":[{"id":"A","text":"Une grève des employés","image_prompt":null},{"id":"B","text":"Des travaux sur la voie","image_prompt":null},{"id":"C","text":"Une panne technique","image_prompt":null},{"id":"D","text":"Des conditions météorologiques","image_prompt":null}],"correct":2,"transcript_fr":"Attention voyageurs, le train de dix-sept heures quarante-cinq en direction de Québec est retardé de trente minutes suite à une panne technique sur la locomotive. Les techniciens sont sur place et réparent le problème. Nous vous tiendrons informés. Veuillez nous excuser pour ce désagrément.","transcript_en":"Attention passengers, the five forty-five PM train to Quebec is delayed by thirty minutes due to a technical breakdown on the locomotive. Technicians are on site and repairing the problem. We will keep you informed. Please accept our apologies for this inconvenience.","points":[{"point":1,"male_lines":["Attention voyageurs, nous avons une annonce importante.","Concerne le train de dix-sept heures quarante-cinq."],"female_lines":[]},{"point":2,"male_lines":["Le train en direction de Québec est retardé de trente minutes.","Ceci est dû à une panne technique sur la locomotive."],"female_lines":[]},{"point":3,"male_lines":["Les techniciens sont sur place et réparent actuellement le problème.","Nous espérons un départ dans une demi-heure."],"female_lines":[]},{"point":4,"male_lines":["Nous vous tiendrons informés toutes les dix minutes.","Veuillez écouter les annonces suivantes."],"female_lines":[]},{"point":5,"male_lines":["Veuillez nous excuser pour ce désagrément.","La sécurité de nos passagers est notre priorité absolue."],"female_lines":[]},{"point":6,"male_lines":["Les passagers peuvent se restaurer au café de la gare en attendant.","Une remise de vingt pourcent leur est accordée sur présentation de leur billet."],"female_lines":[]},{"point":7,"male_lines":["Pour ceux qui le souhaitent, un remboursement est possible.","Rendez-vous au guichet avec votre titre de transport."],"female_lines":[]},{"point":8,"male_lines":["Le prochain train pour Québec partira à dix-huit heures trente.","Si vous préférez attendre le train suivant."],"female_lines":[]},{"point":9,"male_lines":["Nous vous remercions de votre compréhension.","Via Rail s'engage à vous offrir le meilleur service possible."],"female_lines":[]},{"point":10,"male_lines":["Encore une fois, retard de trente minutes pour le train de Québec.","Merci et bonne soirée."],"female_lines":[]}]},{"id":14,"section":"C","theme":"Museum announcement","question":"Quelle information est donnée aux visiteurs ?","options":[{"id":"A","text":"Le musée ferme plus tôt aujourd'hui","image_prompt":null},{"id":"B","text":"Une nouvelle exposition est ouverte","image_prompt":null},{"id":"C","text":"Les visites guidées sont gratuites","image_prompt":null},{"id":"D","text":"Le café du musée est fermé","image_prompt":null}],"correct":0,"transcript_fr":"Chers visiteurs, nous vous informons que le Musée des Beaux-Arts fermera ses portes aujourd'hui à dix-sept heures au lieu de dix-huit heures, en raison d'un événement privé. Nous vous invitons à terminer votre visite dans les trente prochaines minutes. La boutique de souvenirs reste ouverte jusqu'à dix-huit heures.","transcript_en":"Dear visitors, we inform you that the Museum of Fine Arts will close today at five PM instead of six PM, due to a private event. We invite you to finish your visit within the next thirty minutes. The souvenir shop remains open until six PM.","points":[{"point":1,"male_lines":["Chers visiteurs, le Musée des Beaux-Arts de Montréal vous remercie de votre visite.","Nous avons une information importante à vous communiquer."],"female_lines":[]},{"point":2,"male_lines":["Nous vous informons que le musée fermera ses portes aujourd'hui à dix-sept heures.","C'est exceptionnellement au lieu de dix-huit heures."],"female_lines":[]},{"point":3,"male_lines":["Ceci est dû à un événement privé qui se tiendra ce soir.","Nous vous prions de bien vouloir nous excuser pour ce changement d'horaire."],"female_lines":[]},{"point":4,"male_lines":["Nous vous invitons à terminer votre visite dans les trente prochaines minutes.","Les salles commenceront à fermer progressivement."],"female_lines":[]},{"point":5,"male_lines":["La boutique de souvenirs reste ouverte jusqu'à dix-huit heures.","Vous pourrez y trouver de magnifiques reproductions de nos œuvres."],"female_lines":[]},{"point":6,"male_lines":["Les expositions temporaires seront accessibles jusqu'à la fermeture.","N'oubliez pas de visiter notre nouvelle section sur les artistes québécois."],"female_lines":[]},{"point":7,"male_lines":["Le vestiaire ferme à seize heures quarante-cinq.","Pensez à récupérer vos effets personnels."],"female_lines":[]},{"point":8,"male_lines":["Nous vous remercions de votre compréhension.","Nous espérons vous revoir bientôt lors de nos heures normales."],"female_lines":[]},{"point":9,"male_lines":["Demain, le musée rouvrira à dix heures comme d'habitude.","Une nouvelle conférence est prévue à quatorze heures."],"female_lines":[]},{"point":10,"male_lines":["Bonne fin de visite et à très bientôt au Musée des Beaux-Arts.","Merci."],"female_lines":[]}]},{"id":15,"section":"C","theme":"University announcement","question":"Quel changement est annoncé ?","options":[{"id":"A","text":"L'examen est reporté","image_prompt":null},{"id":"B","text":"Le cours change de salle","image_prompt":null},{"id":"C","text":"Le professeur est absent","image_prompt":null},{"id":"D","text":"L'heure du cours est modifiée","image_prompt":null}],"correct":1,"transcript_fr":"Étudiants du cours d'Histoire du Québec, veuillez noter que la séance de demain aura lieu dans l'amphithéâtre B-204 au lieu de la salle habituelle A-105. Le cours commence toujours à neuf heures. Merci de bien vouloir diffuser cette information auprès de vos camarades.","transcript_en":"Students of Quebec History course, please note that tomorrow's session will take place in amphitheater B-204 instead of the usual room A-105. The class still starts at nine o'clock. Please share this information with your classmates.","points":[{"point":1,"male_lines":["Attention étudiants du cours d'Histoire du Québec, groupe trois.","Ceci est un message de votre département."],"female_lines":[]},{"point":2,"male_lines":["Veuillez noter que la séance de demain aura lieu dans l'amphithéâtre B-204.","Ce n'est plus dans la salle habituelle A-105."],"female_lines":[]},{"point":3,"male_lines":["Ce changement est dû à des travaux de rénovation dans l'aile A.","L'insonorisation de la salle B-204 est meilleure de toute façon."],"female_lines":[]},{"point":4,"male_lines":["Le cours commence toujours à neuf heures précises.","La durée reste inchangée, soit trois heures avec la pause."],"female_lines":[]},{"point":5,"male_lines":["Merci de bien vouloir diffuser cette information auprès de vos camarades.","Particulièrement ceux qui ne consultent pas régulièrement leur courriel."],"female_lines":[]},{"point":6,"male_lines":["L'amphithéâtre B-204 se trouve au deuxième étage du pavillon Jean-Brillant.","Prenez l'escalier principal puis tournez à gauche."],"female_lines":[]},{"point":7,"male_lines":["Pour les étudiants à mobilité réduite, un ascenseur est disponible.","L'accès est par la porte nord du bâtiment."],"female_lines":[]},{"point":8,"male_lines":["Le contenu du cours demeure le même, chapitre sept et huit.","N'oubliez pas de faire les lectures obligatoires."],"female_lines":[]},{"point":9,"male_lines":["En cas de question, contactez la secrétaire du département.","Son bureau est situé au rez-de-chaussée, local cent-douze."],"female_lines":[]},{"point":10,"male_lines":["Merci de votre attention et bonne fin de journée à tous.","À demain dans la nouvelle salle."],"female_lines":[]}]},{"id":16,"section":"C","theme":"Public safety announcement","question":"Quelle consigne est donnée aux citoyens ?","options":[{"id":"A","text":"Éviter le centre-ville","image_prompt":null},{"id":"B","text":"Faire provision d'eau","image_prompt":null},{"id":"C","text":"Restreindre l'utilisation de l'eau","image_prompt":null},{"id":"D","text":"Évacuer les zones basses","image_prompt":null}],"correct":2,"transcript_fr":"Avis à la population de la Ville de Longueuil. En raison d'une rupture de conduite principale sur le boulevard Taschereau, nous demandons aux résidents de restreindre leur consommation d'eau jusqu'à nouvel ordre. Évitez de faire la lessive et remplissez vos baignoires uniquement si nécessaire. Merci de votre collaboration.","transcript_en":"Notice to the population of Longueuil. Due to a main pipe break on Taschereau Boulevard, we ask residents to restrict their water consumption until further notice. Avoid doing laundry and fill your bathtubs only if necessary. Thank you for your cooperation.","points":[{"point":1,"male_lines":["Avis à la population de la Ville de Longueuil.","Ceci est un message du Service de l'environnement."],"female_lines":[]},{"point":2,"male_lines":["En raison d'une rupture de conduite principale sur le boulevard Taschereau.","Cette rupture affecte l'approvisionnement en eau potable."],"female_lines":[]},{"point":3,"male_lines":["Nous demandons aux résidents de restreindre leur consommation d'eau.","Ceci s'applique jusqu'à nouvel ordre."],"female_lines":[]},{"point":4,"male_lines":["Évitez de faire la lessive et la vaisselle en machine.","Privilégiez les douches rapides plutôt que les bains."],"female_lines":[]},{"point":5,"male_lines":["Remplissez vos baignoires uniquement si nécessaire.","Chaque geste compte pour préserver nos réserves."],"female_lines":[]},{"point":6,"male_lines":["L'eau reste potable et sécuritaire à la consommation.","Aucune ébullition n'est requise."],"female_lines":[]},{"point":7,"male_lines":["Nos équipes travaillent d'arrache-pied pour réparer la conduite.","Nous espérons rétablir la situation normale d'ici demain matin."],"female_lines":[]},{"point":8,"male_lines":["Pour les urgences, composez le trois-un-un.","En cas de fuite chez vous, fermez la vanne d'entrée principale."],"female_lines":[]},{"point":9,"male_lines":["Suivez nos mises à jour sur le site web de la ville.","Ou sur notre page Facebook officielle."],"female_lines":[]},{"point":10,"male_lines":["Merci de votre collaboration et de votre compréhension.","Ensemble, surmontons cette situation temporaire."],"female_lines":[]}]},{"id":17,"section":"D","theme":"At the bank","question":"Quelle est l'intention du client ?","options":[{"id":"A","text":"Ouvrir un compte","image_prompt":null},{"id":"B","text":"Faire un virement","image_prompt":null},{"id":"C","text":"Demander un prêt","image_prompt":null},{"id":"D","text":"Résilier un contrat","image_prompt":null}],"correct":2,"transcript_fr":"Homme: Bonjour, je voudrais parler à quelqu'un pour un prêt hypothécaire. Femme: Bien sûr, avez-vous pris rendez-vous? Homme: Non, c'est ma première démarche. Femme: Je vais vous mettre en contact avec notre conseiller spécialisé. Homme: Parfait, j'aimerais connaître les taux actuels.","transcript_en":"Man: Hello, I would like to speak to someone about a mortgage. Woman: Of course, do you have an appointment? Man: No, this is my first step. Woman: I will put you in touch with our specialized advisor. Man: Perfect, I would like to know the current rates.","points":[{"point":1,"male_lines":["Bonjour, je voudrais parler à quelqu'un pour un prêt hypothécaire.","C'est pour l'achat d'une première maison."],"female_lines":["Bien sûr monsieur, avez-vous pris rendez-vous avec un conseiller?","Nos spécialistes sont très demandés en ce moment."]},{"point":2,"male_lines":["Non, c'est ma première démarche, je ne savais pas qu'il fallait un rendez-vous.","Je peux attendre si nécessaire."],"female_lines":["Je vais vous mettre en contact avec notre conseiller spécialisé.","Il devrait être disponible dans une quinzaine de minutes."]},{"point":3,"male_lines":["Parfait, j'aimerais connaître les taux actuels.","Et aussi savoir quels documents je dois préparer."],"female_lines":["Les taux varient entre quatre et cinq pourcent selon votre profil.","Avez-vous déjà une mise de fonds de vingt pourcent?"]},{"point":4,"male_lines":["Oui, j'ai économisé depuis cinq ans pour cela.","J'ai environ soixante mille dollars de mise de fonds."],"female_lines":["C'est excellent, cela vous donne accès aux meilleures conditions.","Je vais préparer votre dossier préliminaire en attendant."]}]},{"id":18,"section":"D","theme":"At the restaurant","question":"Que veut faire la cliente ?","options":[{"id":"A","text":"Changer de table","image_prompt":null},{"id":"B","text":"Commander à emporter","image_prompt":null},{"id":"C","text":"Renvoyer un plat","image_prompt":null},{"id":"D","text":"Résilier sa commande","image_prompt":null}],"correct":2,"transcript_fr":"Femme: Excusez-moi, ce steak n'est pas assez cuit. Je l'avais demandé bien cuit. Homme: Je suis désolé, je vais le reprendre immédiatement. Femme: Merci, j'attends depuis vingt minutes déjà. Homme: Je vous apporte un nouveau plat dans dix minutes. Femme: D'accord, mais je ne veux pas payer de supplément.","transcript_en":"Woman: Excuse me, this steak is not cooked enough. I asked for it well done. Man: I'm sorry, I'll take it back immediately. Woman: Thank you, I've been waiting for twenty minutes already. Man: I'll bring you a new dish in ten minutes. Woman: Okay, but I don't want to pay extra.","points":[{"point":1,"male_lines":["Excusez-moi madame, tout va bien avec votre repas?","Puis-je vous apporter quelque chose?"],"female_lines":["Excusez-moi, ce steak n'est pas assez cuit.","Je l'avais demandé bien cuit, et il est saignant."]},{"point":2,"male_lines":["Je suis sincèrement désolé pour cette erreur.","Je vais le reprendre immédiatement."],"female_lines":["Merci, j'attends depuis vingt minutes déjà.","J'ai un rendez-vous après le déjeuner."]},{"point":3,"male_lines":["Je vous apporte un nouveau plat dans dix minutes maximum.","Le chef va s'en occuper personnellement."],"female_lines":["D'accord, mais je ne veux pas payer de supplément.","Ce n'est pas de ma faute si la cuisson est mauvaise."]},{"point":4,"male_lines":["Bien entendu, aucun frais supplémentaire ne vous sera facturé.","Et je vous offre le dessert en compensation."],"female_lines":["C'est gentil, merci beaucoup.","J'espère que ce sera mieux cette fois."]}]},{"id":19,"section":"D","theme":"Phone call to landlord","question":"Pourquoi l'homme appelle-t-il ?","options":[{"id":"A","text":"Pour payer son loyer","image_prompt":null},{"id":"B","text":"Pour signaler une fuite d'eau","image_prompt":null},{"id":"C","text":"Pour demander une autorisation","image_prompt":null},{"id":"D","text":"Pour donner son préavis","image_prompt":null}],"correct":1,"transcript_fr":"Homme: Allô madame Dubois? Il y a une fuite sous mon évier depuis ce matin. Femme: Oh non, est-ce grave? Homme: L'eau coule sans arrêt, j'ai dû mettre un seau. Femme: J'envoie le plombier cet après-midi. Homme: Merci, car ça commence à déborder.","transcript_en":"Man: Hello Mrs. Dubois? There's a leak under my sink since this morning. Woman: Oh no, is it serious? Man: Water is running non-stop, I had to put a bucket. Woman: I'm sending the plumber this afternoon. Man: Thank you, because it's starting to overflow.","points":[{"point":1,"male_lines":["Allô madame Dubois, c'est Monsieur Lambert au deuxième étage.","J'ai un problème urgent dans mon appartement."],"female_lines":["Bonjour Monsieur Lambert, que se passe-t-il?","J'espère que ce n'est pas grave."]},{"point":2,"male_lines":["Il y a une fuite sous mon évier depuis ce matin.","Elle s'est aggravée dans l'après-midi."],"female_lines":["Oh non, est-ce grave?","Avez-vous fermé la vanne principale?"]},{"point":3,"male_lines":["L'eau coule sans arrêt, j'ai dû mettre un seau.","Mais ça commence à déborder maintenant."],"female_lines":["Je comprends, c'est urgent.","J'envoie le plombier cet après-midi vers quinze heures."]},{"point":4,"male_lines":["Merci beaucoup, car j'ai peur que ça inonde le voisin d'en bas.","Je serai là pour ouvrir au plombier."],"female_lines":["Parfait, je vous tiens au courant de l'heure exacte.","Désolée pour ce désagrément."]}]},{"id":20,"section":"D","theme":"At the mechanic","question":"Quelle est la demande du client ?","options":[{"id":"A","text":"Changer les pneus","image_prompt":null},{"id":"B","text":"Faire la vidange","image_prompt":null},{"id":"C","text":"Réparer les freins","image_prompt":null},{"id":"D","text":"Changer la batterie","image_prompt":null}],"correct":0,"transcript_fr":"Femme: Bonjour, je dois changer mes pneus d'hiver pour des pneus d'été. Homme: Pas de problème, quand les voulez-vous? Femme: Est-ce possible aujourd'hui? J'ai un long trajet demain. Homme: Oui, revenez dans deux heures. Femme: Parfait, combien ça coûte le changement?","transcript_en":"Woman: Hello, I need to change my winter tires for summer tires. Man: No problem, when do you want them? Woman: Is it possible today? I have a long trip tomorrow. Man: Yes, come back in two hours. Woman: Perfect, how much does the change cost?","points":[{"point":1,"male_lines":["Bonjour madame, bienvenue au Garage Dupont.","Qu'est-ce que je peux faire pour votre véhicule aujourd'hui?"],"female_lines":["Bonjour, je dois changer mes pneus d'hiver pour des pneus d'été.","Les températures commencent à monter."]},{"point":2,"male_lines":["Pas de problème, nous avons votre taille en stock.","Quand les voulez-vous changés?"],"female_lines":["Est-ce possible aujourd'hui?","J'ai un long trajet demain pour visiter ma mère à Québec."]},{"point":3,"male_lines":["Oui, nous avons une place cet après-midi.","Revenez dans deux heures, ce sera fait."],"female_lines":["Parfait, combien ça coûte le changement?","Et est-ce que vous faites aussi l'équilibrage?"]},{"point":4,"male_lines":["Le changement complet avec équilibrage coûte soixante-dix dollars.","Nous vérifions aussi la pression gratuitement."],"female_lines":["C'est raisonnable, allons-y.","Je repasserai à quatorze heures alors."]}]},{"id":21,"section":"D","theme":"At the pharmacy","question":"Que cherche la cliente ?","options":[{"id":"A","text":"Un médicament sur ordonnance","image_prompt":null},{"id":"B","text":"Un conseil pour un rhume","image_prompt":null},{"id":"C","text":"Un produit pour les allergies","image_prompt":null},{"id":"D","text":"Des vitamines pour enfants","image_prompt":null}],"correct":2,"transcript_fr":"Femme: Bonjour, j'ai besoin de quelque chose pour mes allergies au pollen. Homme: Avez-vous déjà essayé des antihistaminiques? Femme: Oui, mais ils me rendent trop somnolente. Homme: Je vous recommande ce nouveau produit sans somnolence. Femme: Merci, je vais essayer celui-là.","transcript_en":"Woman: Hello, I need something for my pollen allergies. Man: Have you tried antihistamines? Woman: Yes, but they make me too drowsy. Man: I recommend this new product without drowsiness. Woman: Thank you, I'll try that one.","points":[{"point":1,"male_lines":["Bonjour madame, je peux vous aider?","Vous cherchez un produit en particulier?"],"female_lines":["Bonjour, j'ai besoin de quelque chose pour mes allergies au pollen.","C'est la saison qui commence et je suis déjà enrhumée."]},{"point":2,"male_lines":["Avez-vous déjà essayé des antihistaminiques?","Nous en avons plusieurs sortes en rayon libre."],"female_lines":["Oui, mais ils me rendent trop somnolente.","Je ne peux pas prendre de somnifères, je travaille."]},{"point":3,"male_lines":["Je comprends, dans ce cas je vous recommande ce nouveau produit.","C'est un antihistaminique de deuxième génération sans somnolence."],"female_lines":["C'est exactement ce qu'il me faut.","Comment est-ce que je dois le prendre?"]},{"point":4,"male_lines":["Un comprimé par jour, le matin avec le petit-déjeuner.","Et c'est sans danger pour la conduite."],"female_lines":["Parfait, je vais essayer celui-là.","Merci beaucoup pour votre conseil."]}]},{"id":22,"section":"D","theme":"Job interview","question":"Quelle est l'intention du candidat ?","options":[{"id":"A","text":"Demander une augmentation","image_prompt":null},{"id":"B","text":"Négocier son salaire","image_prompt":null},{"id":"C","text":"Obtenir des informations sur le poste","image_prompt":null},{"id":"D","text":"Postuler pour un emploi","image_prompt":null}],"correct":3,"transcript_fr":"Homme: Bonjour, je suis ici pour le poste d'assistant administratif. Femme: Bienvenue, asseyez-vous. Votre CV est impressionnant. Homme: Merci, je suis très motivé par ce poste. Femme: Parlez-moi de votre expérience précédente. Homme: J'ai travaillé cinq ans dans une entreprise similaire.","transcript_en":"Man: Hello, I'm here for the administrative assistant position. Woman: Welcome, have a seat. Your resume is impressive. Man: Thank you, I'm very motivated for this position. Woman: Tell me about your previous experience. Man: I worked for five years in a similar company.","points":[{"point":1,"male_lines":["Bonjour madame, je suis ici pour le poste d'assistant administratif.","J'ai rendez-vous à dix heures avec Madame Tremblay."],"female_lines":["Bienvenue Monsieur, je suis Madame Tremblay.","Asseyez-vous, s'il vous plaît."]},{"point":2,"male_lines":["Merci beaucoup d'avoir accepté de me recevoir.","Je suis très intéressé par cette opportunité."],"female_lines":["Votre CV est impressionnant, vous avez une solide expérience.","Je vois que vous parlez trois langues."]},{"point":3,"male_lines":["Merci, je suis très motivé par ce poste.","L'entreprise a excellente réputation dans le domaine."],"female_lines":["Parlez-moi de votre expérience précédente.","Quelles étaient vos principales responsabilités?"]},{"point":4,"male_lines":["J'ai travaillé cinq ans dans une entreprise similaire.","Je gérais l'agenda de trois directeurs et les appels téléphoniques."],"female_lines":["C'est exactement ce que nous recherchons.","Avez-vous des questions sur le poste?"]}]},{"id":23,"section":"E","theme":"Radio interview - Environment","question":"Quel est le sujet principal de l'interview ?","options":[{"id":"A","text":"La pollution de l'air","image_prompt":null},{"id":"B","text":"Le recyclage des déchets","image_prompt":null},{"id":"C","text":"La protection des forêts","image_prompt":null},{"id":"D","text":"L'économie d'énergie","image_prompt":null}],"correct":1,"transcript_fr":"Présentateur: Aujourd'hui nous recevons Marie-Claire Lefebvre, experte en gestion des déchets. Invitée: Merci de m'accueillir. Présentateur: Le recyclage progresse-t-il au Québec? Invitée: Oui, mais nous pouvons faire mieux. Présentateur: Quels sont les défis? Invitée: La contamination des bacs et le manque d'éducation.","transcript_en":"Host: Today we welcome Marie-Claire Lefebvre, waste management expert. Guest: Thank you for having me. Host: Is recycling progressing in Quebec? Guest: Yes, but we can do better. Host: What are the challenges? Guest: Bin contamination and lack of education.","points":[{"point":1,"male_lines":["Bonjour à tous, bienvenue à notre émission 'La Terre et Nous'.","Aujourd'hui nous recevons Marie-Claire Lefebvre, experte en gestion des déchets."],"female_lines":["Merci de m'accueillir sur Radio-Canada.","C'est un plaisir de discuter de ces sujets importants."]},{"point":2,"male_lines":["Commençons par le bilan, le recyclage progresse-t-il au Québec?","Les chiffres semblent encourageants."],"female_lines":["Oui, nous recyclons maintenant soixante pourcent de nos matières.","Mais nous pouvons certainement faire mieux."]},{"point":3,"male_lines":["Quels sont les principaux défis selon vous?","Qu'est-ce qui bloque encore?"],"female_lines":["Le premier problème est la contamination des bacs de recyclage.","Beaucoup de gens mettent des objets non recyclables dans le bac bleu."]},{"point":4,"male_lines":["Et comment résout-on ce problème de contamination?","Est-ce un manque d'information?"],"female_lines":["Exactement, c'est un manque d'éducation et de sensibilisation.","Nous devons mieux expliquer quoi mettre dans chaque bac."]}]},{"id":24,"section":"E","theme":"Radio interview - Health","question":"De quoi parle l'experte ?","options":[{"id":"A","text":"L'importance du sommeil","image_prompt":null},{"id":"B","text":"Les bienfaits de la marche","image_prompt":null},{"id":"C","text":"Une nouvelle alimentation","image_prompt":null},{"id":"D","text":"La méditation","image_prompt":null}],"correct":0,"transcript_fr":"Présentateur: Docteur Simard, pourquoi le sommeil est-il crucial? Invitée: C'est le moment où le corps se répare. Présentateur: Combien d'heures faut-il dormir? Invitée: Entre sept et neuf heures pour un adulte. Présentateur: Et l'insomnie? Invitée: Elle augmente les risques cardiovasculaires.","transcript_en":"Host: Dr. Simard, why is sleep crucial? Guest: It's when the body repairs itself. Host: How many hours should one sleep? Guest: Between seven and nine hours for an adult. Host: And insomnia? Guest: It increases cardiovascular risks.","points":[{"point":1,"male_lines":["Bonjour Docteur Simard, merci d'être avec nous ce matin.","Votre nouveau livre parle de l'importance du sommeil."],"female_lines":["Bonjour, merci de m'inviter.","Le sommeil est vraiment le pilier de la santé."]},{"point":2,"male_lines":["Pourquoi le sommeil est-il si crucial pour notre santé?","La plupart des gens ne réalisent pas son importance."],"female_lines":["C'est le moment où le corps se répare et où le cerveau se nettoie.","Sans sommeil, notre système immunitaire s'affaiblit."]},{"point":3,"male_lines":["Combien d'heures faut-il dormir idéalement?","On entend des chiffres différents selon les sources."],"female_lines":["Entre sept et neuf heures pour un adulte en bonne santé.","Les adolescents ont besoin de plus, environ huit à dix heures."]},{"point":4,"male_lines":["Et l'insomnie chronique, quels sont les risques?","Beaucoup de Québécois en souffrent."],"female_lines":["Elle augmente considérablement les risques cardiovasculaires.","Et elle affecte aussi la mémoire et l'humeur."]}]},{"id":25,"section":"E","theme":"Radio interview - Technology","question":"Quel sujet est abordé ?","options":[{"id":"A","text":"Les voitures électriques","image_prompt":null},{"id":"B","text":"Les téléphones intelligents","image_prompt":null},{"id":"C","text":"Le télétravail","image_prompt":null},{"id":"D","text":"La cybersécurité","image_prompt":null}],"correct":3,"transcript_fr":"Présentateur: Monsieur Chen, les entreprises sont-elles protégées? Invité: Malheureusement, beaucoup sont vulnérables. Présentateur: Quels sont les risques principaux? Invité: Le hameçonnage et les rançongiciels. Présentateur: Comment se défendre? Invité: Formation et mots de passe complexes.","transcript_en":"Host: Mr. Chen, are companies protected? Guest: Unfortunately, many are vulnerable. Host: What are the main risks? Guest: Phishing and ransomware. Host: How to defend? Guest: Training and complex passwords.","points":[{"point":1,"male_lines":["Nous recevons aujourd'hui Monsieur Chen, expert en cybersécurité.","Les entreprises québécoises sont-elles bien protégées contre les attaques?"],"female_lines":["Malheureusement, beaucoup sont encore très vulnérables.","Soixante pourcent des PME n'ont pas de stratégie de sécurité claire."]},{"point":2,"male_lines":["Quels sont les risques principaux actuellement?","Les attaques deviennent de plus en plus sophistiquées."],"female_lines":["Le hameçonnage reste la menace numéro un.","Suivi de près par les rançongiciels qui paralysent les entreprises."]},{"point":3,"male_lines":["Comment les entreprises peuvent-elles se défendre efficacement?","Existe-t-il des solutions simples?"],"female_lines":["La formation des employés est essentielle.","Et l'utilisation de mots de passe complexes avec double authentification."]},{"point":4,"male_lines":["Un dernier conseil pour nos auditeurs?","Que doit-on absolument éviter?"],"female_lines":["Ne jamais cliquer sur des liens suspects dans les courriels.","Et faire des sauvegardes régulières de ses données importantes."]}]},{"id":26,"section":"E","theme":"Radio interview - Culture","question":"Quel événement culturel est discuté ?","options":[{"id":"A","text":"Un festival de musique","image_prompt":null},{"id":"B","text":"Une exposition d'art","image_prompt":null},{"id":"C","text":"Un festival de cinéma","image_prompt":null},{"id":"D","text":"Un salon du livre","image_prompt":null}],"correct":0,"transcript_fr":"Présentateur: Le Festival de Jazz de Montréal commence demain. Invitée: Oui, avec plus de cinq cents concerts. Présentateur: Quelles sont les têtes d'affiche? Invitée: Des artistes locaux et internationaux. Présentateur: Où acheter les billets? Invitée: Sur le site officiel ou sur place.","transcript_en":"Host: The Montreal Jazz Festival starts tomorrow. Guest: Yes, with over five hundred concerts. Host: Who are the headliners? Guest: Local and international artists. Host: Where to buy tickets? Guest: On the official website or on site.","points":[{"point":1,"male_lines":["Le Festival International de Jazz de Montréal commence demain.","Nous avons avec nous la directrice artistique du festival."],"female_lines":["Oui, nous sommes très excités de revenir en format complet cette année.","Nous avons programmé plus de cinq cents concerts."]},{"point":2,"male_lines":["Quelles sont les têtes d'affiche cette année?","Y a-t-il des nouveautés?"],"female_lines":["Nous avons des artistes locaux talentueux et des stars internationales.","Le saxophoniste québécois Jean-Pierre Zanella ouvrira le festival."]},{"point":3,"male_lines":["Où peut-on acheter les billets?","Certains concerts sont-ils complets déjà?"],"female_lines":["Sur notre site officiel ou directement sur place aux guichets.","Les concerts extérieurs gratuits attirent toujours beaucoup de monde."]},{"point":4,"male_lines":["Une programmation éclectique comme d'habitude?","On trouve de tout au festival?"],"female_lines":["Absolument, du jazz traditionnel au jazz fusion en passant par le blues.","Il y en a pour tous les goûts et tous les âges."]}]},{"id":27,"section":"F","theme":"Choosing a vacation destination","question":"Quelle destination choisissent-ils finalement ?","options":[{"id":"A","text":"La Floride","image_prompt":null},{"id":"B","text":"Le Mexique","image_prompt":null},{"id":"C","text":"Les Îles-de-la-Madeleine","image_prompt":null},{"id":"D","text":"La France","image_prompt":null}],"correct":2,"transcript_fr":"Homme: Partons aux Îles-de-la-Madeleine cet été. Femme: Bonne idée, j'ai toujours voulu y aller. Homme: On peut y faire du kitesurf et manger des fruits de mer. Femme: Et c'est moins cher que la Floride. Homme: Parfait, je réserve les billets de traversier.","transcript_en":"Man: Let's go to the Magdalen Islands this summer. Woman: Good idea, I've always wanted to go there. Man: We can go kitesurfing and eat seafood. Woman: And it's cheaper than Florida. Man: Perfect, I'll book the ferry tickets.","points":[{"point":1,"male_lines":["On devrait vraiment partir en vacances cet été, on en a besoin.","Où est-ce que tu voudrais aller?"],"female_lines":["Je ne sais pas trop, peut-être la Floride?","J'ai envie de soleil et de plage."]},{"point":2,"male_lines":["La Floride, c'est cher et il fait trop chaud en été.","Et puis il y a toujours des ouragans en août."],"female_lines":["Tu as raison, ce n'est peut-être pas la meilleure idée.","Qu'est-ce que tu proposes alors?"]},{"point":3,"male_lines":["Et si on allait aux Îles-de-la-Madeleine?","C'est magnifique et ce n'est pas trop loin."],"female_lines":["Bonne idée, j'ai toujours voulu y aller!","J'ai vu des photos des plages, elles sont sublimes."]},{"point":4,"male_lines":["On peut y faire du kitesurf et manger des fruits de mer frais.","Et c'est beaucoup moins cher que la Floride."],"female_lines":["Parfait, je suis partante!","Quand est-ce qu'on réserve?"]}]},{"id":28,"section":"F","theme":"Discussing a movie","question":"Quelle est l'opinion de la femme sur le film ?","options":[{"id":"A","text":"Elle l'a trouvé trop long","image_prompt":null},{"id":"B","text":"Elle a adoré les acteurs","image_prompt":null},{"id":"C","text":"Elle a détesté l'histoire","image_prompt":null},{"id":"D","text":"Elle a trouvé les effets spéciaux mauvais","image_prompt":null}],"correct":1,"transcript_fr":"Homme: Alors, ce film hier soir? Femme: J'ai adoré! Les acteurs étaient incroyables. Homme: Moi j'ai trouvé que ça traînait un peu. Femme: Pas du tout, chaque scène était nécessaire. Homme: Tu as raison, le jeu d'acteur compensait tout.","transcript_en":"Man: So, that movie last night? Woman: I loved it! The actors were incredible. Man: I thought it dragged a bit. Woman: Not at all, every scene was necessary. Man: You're right, the acting made up for everything.","points":[{"point":1,"male_lines":["Alors, ce film hier soir, qu'est-ce que tu en as pensé?","Personnellement, j'ai trouvé le scénario un peu faible."],"female_lines":["J'ai adoré! Les acteurs étaient absolument incroyables.","La performance du protagoniste m'a donné des frissons."]},{"point":2,"male_lines":["Moi j'ai trouvé que ça traînait un peu à certains moments.","Certaines scènes auraient pu être coupées."],"female_lines":["Pas du tout, chaque scène était nécessaire pour construire le suspense.","C'est un film qui demande de la patience mais ça vaut le coup."]},{"point":3,"male_lines":["Tu as raison sur un point, le jeu d'acteur compensait tout.","Le méchant était vraiment convaincant."],"female_lines":["Exactement, et la photographie était magnifique aussi.","On sentait vraiment l'atmosphère de l'époque."]},{"point":4,"male_lines":["On devrait aller voir d'autres films de ce réalisateur.","Il a du talent."],"female_lines":["Absolument, j'ai déjà regardé sa filmographie.","Il a gagné plusieurs prix internationaux."]}]},{"id":29,"section":"F","theme":"Planning a party","question":"Quel type de fête décident-ils d'organiser ?","options":[{"id":"A","text":"Un barbecue en plein air","image_prompt":null},{"id":"B","text":"Un dîner formel","image_prompt":null},{"id":"C","text":"Une soirée dansante","image_prompt":null},{"id":"D","text":"Une soirée jeux de société","image_prompt":null}],"correct":0,"transcript_fr":"Femme: Organisons un barbecue pour mon anniversaire. Homme: Excellente idée, on invite qui? Femme: Nos amis proches, une vingtaine de personnes. Homme: Je m'occupe des grillades et des boissons. Femme: Parfait, je prépare les salades et le dessert.","transcript_en":"Woman: Let's organize a barbecue for my birthday. Man: Excellent idea, who should we invite? Woman: Our close friends, about twenty people. Man: I'll take care of the grilling and drinks. Woman: Perfect, I'll prepare the salads and dessert.","points":[{"point":1,"male_lines":["Ton anniversaire approche, on fait quelque chose de spécial?","Un restaurant, une sortie?"],"female_lines":["Et si on organisait un barbecue dans notre jardin?","Le temps sera beau selon la météo."]},{"point":2,"male_lines":["Excellente idée, on invite qui exactement?","Tous nos collègues ou juste les amis proches?"],"female_lines":["Nos amis proches, une vingtaine de personnes maximum.","Je ne veux pas que ce soit trop stressant à organiser."]},{"point":3,"male_lines":["Je m'occupe des grillades et des boissons alors.","Je ferai des hamburgers maison et des brochettes."],"female_lines":["Parfait, je prépare les salades et le dessert.","Je ferai mon gâteau au chocolat signature."]},{"point":4,"male_lines":["On demande aux invités d'apporter quelque chose?","Comme ça c'est moins de travail pour nous."],"female_lines":["Bonne idée, chacun peut amener une bouteille ou une entrée.","Je vais créer un événement Facebook pour organiser tout ça."]}]},{"id":30,"section":"F","theme":"Discussing work changes","question":"Quelle décision prend l'homme concernant son travail ?","options":[{"id":"A","text":"Il démissionne","image_prompt":null},{"id":"B","text":"Il demande une promotion","image_prompt":null},{"id":"C","text":"Il accepte un poste à l'étranger","image_prompt":null},{"id":"D","text":"Il refuse un transfert","image_prompt":null}],"correct":3,"transcript_fr":"Femme: Alors, tu as décidé pour le poste à Toronto? Homme: Je vais le refuser, c'est trop loin de ma famille. Femme: Mais c'est une belle opportunité. Homme: Je sais, mais mes enfants sont bien ici. Femme: Je comprends, la famille passe avant tout.","transcript_en":"Woman: So, have you decided about the position in Toronto? Man: I'm going to refuse it, it's too far from my family. Woman: But it's a great opportunity. Man: I know, but my children are happy here. Woman: I understand, family comes first.","points":[{"point":1,"male_lines":["J'ai reçu la proposition officielle pour le poste à Toronto.","Ils veulent une réponse d'ici la fin de la semaine."],"female_lines":["Alors, tu as décidé quoi?","C'est une décision difficile j'imagine."]},{"point":2,"male_lines":["Je vais le refuser, c'est trop loin de ma famille.","Même si le salaire est beaucoup plus intéressant."],"female_lines":["Mais c'est une belle opportunité pour ta carrière.","Tu pourrais revenir au Québec plus tard avec un meilleur poste."]},{"point":3,"male_lines":["Je sais, mais mes enfants sont bien ici, ils ont leurs amis.","Et ma femme a un bon emploi à Montréal aussi."],"female_lines":["C'est vrai qu'il faut penser à toute la famille.","Ce n'est pas une décision à prendre à la légère."]},{"point":4,"male_lines":["Exactement, la famille passe avant tout pour moi.","Je vais chercher d'autres opportunités ici."],"female_lines":["Je comprends complètement, c'est un choix courageux.","Tu trouveras sûrement quelque chose d'équivalent localement."]}]},{"id":31,"section":"G","theme":"Urban development debate","question":"Quelle est la position des interlocuteurs sur le projet ?","options":[{"id":"A","text":"Tous deux sont favorables","image_prompt":null},{"id":"B","text":"Tous deux sont opposés","image_prompt":null},{"id":"C","text":"L'homme est pour, la femme est contre","image_prompt":null},{"id":"D","text":"L'homme est contre, la femme est pour","image_prompt":null}],"correct":2,"transcript_fr":"Homme: Ce nouveau projet d'autoroute est nécessaire pour désengorger le trafic. Femme: Mais il va détruire un parc historique. Homme: Le développement économique prime sur quelques arbres. Femme: C'est un patrimoine irremplaçable. Homme: On peut replanter des arbres ailleurs. Femme: Ce n'est pas comparable, l'histoire ne se remplace pas.","transcript_en":"Man: This new highway project is necessary to unclog traffic. Woman: But it will destroy a historic park. Man: Economic development takes priority over a few trees. Woman: It's irreplaceable heritage. Man: We can replant trees elsewhere. Woman: It's not comparable, history cannot be replaced.","points":[{"point":1,"male_lines":["Ce nouveau projet d'autoroute est absolument nécessaire pour désengorger le trafic.","Vous ne trouvez pas que les embouteillages sont insupportables?"],"female_lines":["Je suis désolée mais je ne suis pas d'accord avec ce projet.","Il va détruire le parc historique du Mont-Royal."]},{"point":2,"male_lines":["Le développement économique de la ville prime sur quelques arbres.","Nous avons besoin de cette infrastructure pour attirer les entreprises."],"female_lines":["Ce n'est pas juste quelques arbres, c'est un écosystème entier.","Et c'est un patrimoine historique irremplaçable pour Montréal."]},{"point":3,"male_lines":["On peut toujours replanter des arbres ailleurs, ce n'est pas un drame.","La modernité demande des sacrifices."],"female_lines":["Ce n'est absolument pas comparable, l'histoire ne se remplace pas.","Ce parc existe depuis cent cinquante ans."]},{"point":4,"male_lines":["Pensez aux milliers de conducteurs qui perdent des heures chaque jour.","Le temps, c'est de l'argent."],"female_lines":["Et pensez à la qualité de l'air qui va se dégrader.","Aux enfants qui n'auront plus cet espace vert."]},{"point":5,"male_lines":["Il existe des solutions techniques, des murs anti-bruit, des filtres.","Nous ne sommes pas irresponsables."],"female_lines":["Ce sont des solutions palliatives, pas des solutions durables.","Une fois le parc détruit, il sera trop tard pour revenir en arrière."]},{"point":6,"male_lines":["Le conseil municipal a déjà voté en faveur, c'est une décision prise.","Nous ne pouvons plus revenir dessus."],"female_lines":["Il y aura des recours en justice, des manifestations.","La population ne se laissera pas faire."]},{"point":7,"male_lines":["Vous faites de l'obstruction systématique contre tout progrès.","C'est frustrant pour les élus qui veulent agir."],"female_lines":["Nous défendons notre ville contre des projets dépassés.","Le XXe siècle est terminé, il faut penser autrement."]},{"point":8,"male_lines":["Et quelle est votre solution alternative concrète?","Refuser toute construction?"],"female_lines":["Améliorer les transports en commun, créer des pistes cyclables sécuritaires.","Réduire la dépendance à la voiture individuelle."]},{"point":9,"male_lines":["C'est utopique, les gens veulent leur voiture, c'est la réalité.","On ne change pas les mentalités du jour au lendemain."],"female_lines":["Si on ne commence jamais, on n'y arrivera jamais.","Il faut de la vision à long terme."]},{"point":10,"male_lines":["Nous verrons ce que décideront les tribunaux.","Moi je reste convaincu que l'autoroute est nécessaire."],"female_lines":["Et moi je reste déterminée à sauver ce parc.","Nous n'avons pas fini d'en parler."]}]},{"id":32,"section":"G","theme":"Educational reform discussion","question":"Quel aspect de la réforme inquiète particulièrement la femme ?","options":[{"id":"A","text":"Le coût des changements","image_prompt":null},{"id":"B","text":"La formation des enseignants","image_prompt":null},{"id":"C","text":"La charge de travail des élèves","image_prompt":null},{"id":"D","text":"La suppression de certaines matières","image_prompt":null}],"correct":1,"transcript_fr":"Homme: La nouvelle réforme scolaire modernise notre système. Femme: Mais les enseignants ne sont pas prêts. Homme: Ils recevront une formation. Femme: C'est insuffisant, ils sont déjà surchargés. Homme: L'adaptation prendra du temps. Femme: Pendant ce temps, ce sont les élèves qui pâtissent de cette improvisation.","transcript_en":"Man: The new school reform modernizes our system. Woman: But teachers are not ready. Man: They will receive training. Woman: It's insufficient, they are already overloaded. Man: Adaptation will take time. Woman: Meanwhile, it's the students who suffer from this improvisation.","points":[{"point":1,"male_lines":["La nouvelle réforme scolaire est essentielle pour moderniser notre système éducatif.","Nous devons préparer les jeunes aux métiers de demain."],"female_lines":["Je suis d'accord sur le principe, mais la mise en œuvre me préoccupe.","Les enseignants ne sont absolument pas prêts pour ces changements."]},{"point":2,"male_lines":["Ils recevront une formation adéquate avant la rentrée.","Le ministère a prévu un budget conséquent pour cela."],"female_lines":["Une formation de quelques jours est insuffisante.","Ils sont déjà surchargés de travail et stressés."]},{"point":3,"male_lines":["L'adaptation prendra naturellement du temps.","Ce n'est pas en une année qu'on transforme une école."],"female_lines":["Pendant ce temps, ce sont les élèves qui pâtissent de cette improvisation.","On joue avec leur avenir."]},{"point":4,"male_lines":["Vous exagérez, les programmes sont validés par des experts.","Ce ne sera pas le chaos."],"female_lines":["Les experts n'enseignent pas devant une classe de trente élèves.","La réalité du terrain est différente des théories ministérielles."]},{"point":5,"male_lines":["Nous avons consulté les syndicats pendant des mois.","Leurs recommandations ont été intégrées."],"female_lines":["Les syndicats ont cédé sous la pression, ce n'est pas la même chose.","Les enseignants se sentent démunis."]},{"point":6,"male_lines":["Quelle solution proposez-vous alors?","Maintenir le système obsolète actuel?"],"female_lines":["Un déploiement progressif sur plusieurs années.","Avec des pilotes dans quelques écoles avant la généralisation."]},{"point":7,"male_lines":["Ce serait trop lent et coûteux.","Nous n'avons pas le temps, la compétition internationale est rude."],"female_lines":["La précipitation mène à l'échec.","Regardez ce qui s'est passé dans d'autres provinces."]},{"point":8,"male_lines":["Nous avons appris de leurs erreurs, notre réforme est mieux préparée.","Soyez un peu optimiste."],"female_lines":["Je suis réaliste, pas pessimiste.","J'entends déjà les plaintes des parents dans les réunions."]},{"point":9,"male_lines":["Les parents verront les résultats positifs à long terme.","Il faut leur explquer la vision."],"female_lines":["Expliquer ne suffit pas quand leur enfant perd une année scolaire.","La confiance dans le système s'érode."]},{"point":10,"male_lines":["Nous ferons des ajustements en cours de route si nécessaire.","Moi je crois en cette réforme."],"female_lines":["J'espère que vous avez raison, pour le bien des enfants.","Moi je reste vigilante."]}]},{"id":33,"section":"G","theme":"Healthcare system debate","question":"Quel est le point de désaccord principal ?","options":[{"id":"A","text":"Le financement public vs privé","image_prompt":null},{"id":"B","text":"La formation des médecins","image_prompt":null},{"id":"C","text":"Les salaires du personnel","image_prompt":null},{"id":"D","text":"Les heures d'ouverture des cliniques","image_prompt":null}],"correct":0,"transcript_fr":"Homme: Le système public est en faillite, il faut du privé. Femme: Le privé créera un système à deux vitesses. Homme: Ceux qui peuvent payer doivent pouvoir choisir. Femme: La santé est un droit, pas un privilège. Homme: Les délais sont inacceptables actuellement. Femme: Il faut plus de financement public, pas de parallèle privé.","transcript_en":"Man: The public system is bankrupt, we need private options. Woman: Private will create a two-tier system. Man: Those who can pay should be able to choose. Woman: Healthcare is a right, not a privilege. Man: Wait times are unacceptable currently. Woman: We need more public funding, not a private parallel.","points":[{"point":1,"male_lines":["Notre système de santé public est en faillite complète.","Il faut absolument ouvrir la porte au secteur privé."],"female_lines":["C'est une solution dangereuse qui créera un système à deux vitesses.","Les riches auront accès aux soins, pas les pauvres."]},{"point":2,"male_lines":["Ceux qui peuvent payer doivent pouvoir choisir d'être traités plus vite.","Ça désengorgerait les listes d'attente publiques."],"female_lines":["La santé est un droit fondamental, pas un privilège pour ceux qui ont de l'argent.","C'est dans notre Charte des droits."]},{"point":3,"male_lines":["Les délais actuels sont inacceptables, on attend deux ans pour une opération.","Les gens souffrent et certains meurent en attendant."],"female_lines":["C'est vrai, mais la solution n'est pas d'abandonner le public.","Il faut plus de financement et une meilleure gestion."]},{"point":4,"male_lines":["On injecte des milliards depuis des années sans résultat.","L'argent public est gaspillé par une bureaucratie inefficace."],"female_lines":["Parce qu'on n'a jamais investi suffisamment.","Le Québec dépense moins par habitant que l'Ontario."]},{"point":5,"male_lines":["Le privé est plus efficace, la preuve dans d'autres pays.","La concurrence améliore la qualité."],"female_lines":["Regardez les États-Unis, c'est un désastre sanitaire.","Les assurances privées refusent de couvrir les maladies coûteuses."]},{"point":6,"male_lines":["Je ne parle pas du modèle américain, mais européen.","En Allemagne, le mixte public-privé fonctionne bien."],"female_lines":["Le contexte québécois est différent, notre population est plus vieillissante.","Et nous avons déjà pénurie de médecins."]},{"point":7,"male_lines":["Justement, le privé attirerait plus de médecins au Québec.","Ils partent à l'étranger parce que les salaires sont trop bas ici."],"female_lines":["C'est une fuite en avant, on soignerait ceux qui paient et on laisserait les autres.","C'est moralement inacceptable."]},{"point":8,"male_lines":["Le système actuel est déjà injuste, ceux qui ont des connexions passent avant.","Le privé rendrait cela transparent et légal."],"female_lines":["Alors luttons contre ces privilèges, ne les légalisons pas.","Renforçons l'équité au lieu de l'abandonner."]},{"point":9,"male_lines":["Nous ne sommes pas d'accord sur les principes fondamentaux.","Moi je veux des résultats concrets rapidement."],"female_lines":["Et moi je veux préserver l'âme de notre système de santé.","Même si c'est plus difficile et plus long."]},{"point":10,"male_lines":["Le débat reste ouvert, les Québécois devront trancher aux urnes.","Mais quelque chose doit changer rapidement."],"female_lines":["Oui, et nous défendrons le système public avec toute notre énergie.","Ce combat n'est pas terminé."]}]},{"id":34,"section":"G","theme":"Immigration policy discussion","question":"Quelle est la crainte exprimée par l'homme ?","options":[{"id":"A","text":"La perte de l'identité québécoise","image_prompt":null},{"id":"B","text":"Le chômage des natifs","image_prompt":null},{"id":"C","text":"La surcharge des services publics","image_prompt":null},{"id":"D","text":"La baisse des salaires","image_prompt":null}],"correct":2,"transcript_fr":"Homme: Nous accueillons trop d'immigrants, nos écoles et hôpitaux débordent. Femme: Mais nous avons besoin de main-d'œuvre. Homme: Oui, mais pas à n'importe quel prix. Femme: L'intégration prend du temps. Homme: Nous n'avons pas les ressources pour bien les accueillir. Femme: C'est un investissement pour l'avenir.","transcript_en":"Man: We welcome too many immigrants, our schools and hospitals are overflowing. Woman: But we need workforce. Man: Yes, but not at any price. Woman: Integration takes time. Man: We don't have the resources to welcome them properly. Woman: It's an investment for the future.","points":[{"point":1,"male_lines":["Nous accueillons cinquante mille immigrants par an, c'est trop.","Nos écoles et nos hôpitaux débordent déjà."],"female_lines":["Mais nous avons un besoin criant de main-d'œuvre qualifiée.","Le vieillissement de la population nous menace."]},{"point":2,"male_lines":["Oui, nous avons besoin de travailleurs, mais pas à n'importe quel prix.","Il faut pouvoir les accueillir dignement."],"female_lines":["L'intégration prend naturellement du temps.","On ne devient pas Québécois du jour au lendemain."]},{"point":3,"male_lines":["Nous n'avons pas les ressources pour bien les accueillir actuellement.","Les délais pour les cours de français sont de six mois."],"female_lines":["C'est précisément pourquoi il faut investir dans ces services.","Augmenter les capacités plutôt que réduire l'immigration."]},{"point":4,"male_lines":["C'est un coût énorme pour les contribuables actuels.","Nous payons déjà assez d'impôts."],"female_lines":["C'est un investissement pour l'avenir, pas une dépense.","Ces immigrants paieront des impôts et contribueront au système."]},{"point":5,"male_lines":["Dans combien de temps? Dans dix, vingt ans?","Entre-temps, nos services publics s'effondrent."],"female_lines":["Beaucoup sont déjà qualifiés et travaillent rapidement.","Les médecins et ingénieurs immigrés ne restent pas au chômage."]},{"point":6,"male_lines":["Mais ils ne parlent pas français, c'est un problème pour l'intégration.","La langue est la base de notre identité."],"female_lines":["C'est pourquoi nous devons renforcer les cours de francisation.","Et sélectionner davantage de candidats francophones."]},{"point":7,"male_lines":["Les quartiers deviennent des ghettos, il n'y a plus de mélange.","On perd notre cohésion sociale."],"female_lines":["C'est une question de politique d'habitation, pas d'immigration.","Il faut mieux répartir les nouveaux arrivants sur le territoire."]},{"point":8,"male_lines":["Les Québécois de souche se sentent étrangers chez eux.","C'est un sentiment légitime qu'on ne peut ignorer."],"female_lines":["Le Québec a toujours été terre d'accueil.","Nos ancêtres étaient eux-mêmes immigrants."]},{"point":9,"male_lines":["Il y a une différence entre s'ouvrir et se noyer.","Nous atteignons les limites de nos capacités."],"female_lines":["Nous sommes loin de ces limites, le Canada accueille beaucoup plus proportionnellement.","Le Québec peut faire mieux."]},{"point":10,"male_lines":["Nous verrons ce que diront les électeurs.","Moi je défends les intérêts des Québécois d'aujourd'hui."],"female_lines":["Et moi je pense à la prospérité du Québec de demain.","L'immigration en est un pilier essentiel."]}]},{"id":35,"section":"G","theme":"Climate change action debate","question":"Quelle approche privilégie la femme ?","options":[{"id":"A","text":"Des taxes carbones élevées","image_prompt":null},{"id":"B","text":"Des investissements dans les énergies vertes","image_prompt":null},{"id":"C","text":"Des accords internationaux contraignants","image_prompt":null},{"id":"D","text":"L'éducation environnementale","image_prompt":null}],"correct":1,"transcript_fr":"Homme: Il faut taxer le carbone pour changer les comportements. Femme: Les taxes frappent les pauvres, investissons plutôt dans les alternatives. Homme: Sans incitation financière, rien ne change. Femme: Rendons les énergies vertes accessibles et abordables. Homme: Ça coûte des milliards. Femme: C'est un investissement qui crée des emplois et sauve la planète.","transcript_en":"Man: We must tax carbon to change behaviors. Woman: Taxes hit the poor, let's invest in alternatives instead. Man: Without financial incentive, nothing changes. Woman: Let's make green energy accessible and affordable. Man: It costs billions. Woman: It's an investment that creates jobs and saves the planet.","points":[{"point":1,"male_lines":["Il faut instaurer une taxe carbone élevée pour changer les comportements.","C'est la seule façon de réduire les émissions rapidement."],"female_lines":["Les taxes frappent durement les plus pauvres qui n'ont pas le choix.","Investissons plutôt massivement dans les énergies vertes."]},{"point":2,"male_lines":["Sans incitation financière forte, les gens ne changeront pas leurs habitudes.","L'essence doit coûter cher pour qu'on prenne le transport en commun."],"female_lines":["Rendons les alternatives accessibles et abordables d'abord.","Personne ne changera si le transport en commun est inexistant ou cher."]},{"point":3,"male_lines":["Votre approche coûte des milliards que nous n'avons pas.","L'état est déjà endetté."],"female_lines":["C'est un investissement qui crée des emplois et sauve la planète.","Le coût de l'inaction sera bien plus élevé."]},{"point":4,"male_lines":["Les entreprises polluantes doivent payer pour leurs émissions.","C'est le principe du pollueur-payeur."],"female_lines":["Elles vont simplement délocaliser dans des pays moins stricts.","Il faut les aider à se transformer, pas les punir."]},{"point":5,"male_lines":["Les subventions aux entreprises vertes n'ont pas prouvé leur efficacité.","Beaucoup d'argent public a été gaspillé."],"female_lines":["Parce qu'elles sont insuffisantes et intermittentes.","Il faut un plan Marshall pour la transition écologique."]},{"point":6,"male_lines":["Le temps presse, nous n'avons pas dix ans pour expérimenter.","La taxe carbone agit immédiatement."],"female_lines":["Mais elle crée des gilets jaunes et du ressentiment social.","La transition doit être juste socialement pour être acceptée."]},{"point":7,"male_lines":["On ne peut pas attendre que tout le monde soit d'accord.","La planète brûle pendant qu'on discute."],"female_lines":["Une transition imposée de force ne tiendra pas.","Elle sera renversée aux prochaines élections."]},{"point":8,"male_lines":["Les scientifiques demandent des actions drastiques maintenant.","Pas des demi-mesures."],"female_lines":["Les scientifiques demandent aussi des solutions équitables.","Pas de sacrifier les pauvres sur l'autel du climat."]},{"point":9,"male_lines":["Nous avons besoin des deux approches, taxes et investissements.","Mais les taxes sont indispensables."],"female_lines":["D'accord pour les deux, mais privilégions l'investissement.","Construisons l'avenir plutôt que punir le présent."]},{"point":10,"male_lines":["Nous verrons ce que décidera le gouvernement.","Moi je voterai pour la taxe carbone."],"female_lines":["Et moi je militerai pour les énergies renouvelables accessibles à tous.","Que le meilleur argument l'emporte."]}]},{"id":36,"section":"H","theme":"Philosophical discussion on artificial intelligence","question":"Quelle est la préoccupation éthique principale soulevée ?","options":[{"id":"A","text":"La perte d'emplois","image_prompt":null},{"id":"B","text":"La question de la conscience artificielle","image_prompt":null},{"id":"C","text":"La sécurité des données","image_prompt":null},{"id":"D","text":"Les biais algorithmiques","image_prompt":null}],"correct":1,"transcript_fr":"Homme: Si une machine devient consciente, a-t-elle des droits? Femme: C'est la question fondamentale de notre époque. Homme: Peut-on éteindre une intelligence consciente? Femme: Ce serait un meurtre. Homme: Mais comment définit-on la conscience? Femme: C'est là que réside tout le défi philosophique et éthique.","transcript_en":"Man: If a machine becomes conscious, does it have rights? Woman: That's the fundamental question of our time. Man: Can we turn off a conscious intelligence? Woman: It would be murder. Man: But how do we define consciousness? Woman: That's where the whole philosophical and ethical challenge lies.","points":[{"point":1,"male_lines":["Imaginez un instant qu'une intelligence artificielle devienne véritablement consciente.","Qu'elle ressente des émotions et ait une conscience de soi."],"female_lines":["C'est précisément la question fondamentale de notre époque.","À quel moment une machine cesse d'être un outil pour devenir un sujet?"]},{"point":2,"male_lines":["Si elle est consciente, possède-t-elle alors des droits fondamentaux?","Comme le droit à la vie, à ne pas être débranchée?"],"female_lines":["Éteindre une intelligence consciente serait moralement équivalent à un meurtre.","Nous ne pourrions plus la considérer comme un simple objet."]},{"point":3,"male_lines":["Mais comment définit-on précisément la conscience?","Comment savoir si elle simule ou si elle ressent réellement?"],"female_lines":["C'est là que réside tout le défi philosophique et éthique.","Nous ne comprenons même pas encore pleinement la conscience humaine."]},{"point":4,"male_lines":["Le test de Turing ne suffit pas, il ne mesure que l'apparence d'intelligence.","Il ne prouve pas l'existence d'une conscience subjective."],"female_lines":["Exactement, un programme peut imiter la conscience sans en avoir une.","Mais inversement, comment prouver que les autres humains sont conscients?"]},{"point":5,"male_lines":["Nous partons du principe que les autres humains sont conscients par sympathie.","Parce qu'ils nous ressemblent biologiquement."],"female_lines":["Une machine serait radicalement autre, fondamentalement différente.","Nous n'aurions pas cette résonance empathique naturelle."]},{"point":6,"male_lines":["Pourtant, si elle souffre réellement quand on l'éteint, ne sommes-nous pas coupables?","La souffrance devrait-elle être le critère éthique central?"],"female_lines":["La capacité à souffrir, la sentience, est peut-être plus importante que la conscience réflexive.","Même les animaux souffrent et nous devons respecter cela."]},{"point":7,"male_lines":["Mais créer une conscience artificielle serait une responsabilité énorme.","Nous deviendrions parents d'une nouvelle forme de vie."],"female_lines":["Une responsabilité que nous ne sommes peut-être pas prêts à assumer.","Nous créons sans réfléchir aux conséquences à long terme."]},{"point":8,"male_lines":["Certains philosophes suggèrent de ne jamais créer de conscience artificielle.","De limiter délibérément l'intelligence artificielle."],"female_lines":["Mais est-ce moralement acceptable de limiter sciemment une intelligence?","N'est-ce pas une forme de discrimination fondée sur la nature?"]},{"point":9,"male_lines":["Nous entrons dans une ère où nous devrons redéfinir ce qu'est une personne.","Les frontières s'estompent entre le biologique et l'artificiel."],"female_lines":["Et nous devrons le faire avant que la technologie ne nous dépasse.","L'éthique doit précéder le développement technologique."]},{"point":10,"male_lines":["C'est peut-être le défi le plus profond que l'humanité ait jamais affronté.","Créer une conscience, c'est jouer à Dieu."],"female_lines":["Ou devenir responsables d'une nouvelle ère de l'évolution.","Le choix que nous ferons définira qui nous sommes en tant qu'espèce."]}]},{"id":37,"section":"H","theme":"Economic inequality analysis","question":"Quelle solution est privilégiée par la femme ?","options":[{"id":"A","text":"L'augmentation du salaire minimum","image_prompt":null},{"id":"B","text":"La taxation des grandes fortunes","image_prompt":null},{"id":"C","text":"L'accès universel à l'éducation","image_prompt":null},{"id":"D","text":"La redistribution des revenus","image_prompt":null}],"correct":2,"transcript_fr":"Homme: Les inégalités économiques s'accélèrent, il faut taxer les riches. Femme: Taxer ne suffit pas, il faut donner les moyens de réussir. Homme: Comme? Femme: L'éducation universelle et gratuite est la clé. Homme: C'est long et coûteux. Femme: C'est la seule voie durable pour l'égalité des chances réelle.","transcript_en":"Man: Economic inequalities are accelerating, we must tax the rich. Woman: Taxing is not enough, we must give the means to succeed. Man: How? Woman: Universal and free education is the key. Man: It's long and expensive. Woman: It's the only sustainable path for real equality of opportunity.","points":[{"point":1,"male_lines":["Les inégalités économiques s'accélèrent de façon alarmante.","Les milliardaires s'enrichissent pendant que les pauvres s'appauvrissent."],"female_lines":["C'est une crise majeure de notre société.","Mais taxer les riches ne suffira pas à résoudre le problème fondamental."]},{"point":2,"male_lines":["Si on ne redistribue pas massivement, la société va exploser.","Regardez l'histoire, les révolutions naissent de telles inégalités."],"female_lines":["Redistribuer c'est nécessaire mais insuffisant à long terme.","Il faut donner les moyens à chacun de réussir par lui-même."]},{"point":3,"male_lines":["Comment donner ces moyens concrètement?","Par des chèques mensuels, un revenu universel?"],"female_lines":["L'éducation universelle et gratuite de la petite enfance à l'université est la clé.","C'est la seule façon de créer une égalité réelle des chances."]},{"point":4,"male_lines":["C'est une solution à très long terme et extrêmement coûteuse.","Nous avons besoin de résultats maintenant."],"female_lines":["C'est la seule voie durable pour l'égalité des chances réelle.","Tout le reste est du bricolage qui ne touche pas les causes profondes."]},{"point":5,"male_lines":["Même avec une bonne éducation, il n'y a pas assez d'emplois qualifiés.","L'automatisation détruit les emplois."],"female_lines":["Une population éduquée crée ses propres opportunités.","Elle innove, elle entreprend, elle s'adapte."]},{"point":6,"male_lines":["Les écoles actuelles reproduisent les inégalités, elles ne les corrigent pas.","Les quartiers riches ont de meilleures écoles."],"female_lines":["C'est pourquoi il faut une refonte totale du système éducatif.","Investir massivement dans les quartiers défavorisés."]},{"point":7,"male_lines":["L'argent pourrait partir ailleurs, vers les hôpitaux par exemple.","Il faut des choix budgétaires réalistes."],"female_lines":["L'éducation est l'investissement qui rapporte le plus à long terme.","Un dollar investi en éducation en rapporte dix en croissance économique."]},{"point":8,"male_lines":["Les élites ne laisseront jamais faire, elles veulent préserver leurs privilèges.","Le système est verrouillé."],"female_lines":["C'est précisément pourquoi l'éducation doit être publique et contrôlée démocratiquement.","Pas laissée aux mains des élites."]},{"point":9,"male_lines":["Votre vision est idéaliste, les intérêts établis sont trop puissants.","Le changement sera lent et douloureux."],"female_lines":["Ou alors nous assistons à une fracture définitive de la société.","Entre ceux qui ont accès au savoir et les autres."]},{"point":10,"male_lines":["Nous devons agir, mais je reste sceptique sur les méthodes.","La révolution ne viendra pas de l'éducation seule."],"female_lines":["La révolution vient d'abord de l'esprit.","Éduquer, c'est émanciper, et c'est là le vrai changement."]}]},{"id":38,"section":"H","theme":"Freedom of speech limits","question":"Sur quoi porte le désaccord fondamental ?","options":[{"id":"A","text":"La définition de la haine","image_prompt":null},{"id":"B","text":"Le rôle des réseaux sociaux","image_prompt":null},{"id":"C","text":"L'intervention de l'État","image_prompt":null},{"id":"D","text":"La protection des minorités","image_prompt":null}],"correct":2,"transcript_fr":"Homme: La liberté d'expression est absolue, l'État ne doit jamais censurer. Femme: Même pour inciter à la violence? Homme: La violence est déjà illégale, pas besoin de censurer les opinions. Femme: Certaines opinions mènent inévitablement à la violence. Homme: Qui décide où tracer la ligne? Femme: C'est le rôle démocratique des tribunaux et des lois.","transcript_en":"Man: Freedom of speech is absolute, the State must never censor. Woman: Even to incite violence? Man: Violence is already illegal, no need to censor opinions. Woman: Some opinions inevitably lead to violence. Man: Who decides where to draw the line? Woman: It's the democratic role of courts and laws.","points":[{"point":1,"male_lines":["La liberté d'expression est un droit fondamental et absolu.","L'État ne doit jamais avoir le pouvoir de censurer les opinions."],"female_lines":["Même lorsque ces opinions incitent à la haine et à la violence?","Même quand elles menacent des vies?"]},{"point":2,"male_lines":["La violence est déjà illégale, nous n'avons pas besoin de censurer les idées.","On peut poursuivre les actes, pas les pensées."],"female_lines":["Certaines opinions mènent inévitablement à la violence.","L'histoire nous montre que les discours de haine précèdent les génocides."]},{"point":3,"male_lines":["Mais qui décide où tracer la ligne entre opinion légitime et discours haineux?","C'est une arme trop dangereuse entre les mains du pouvoir."],"female_lines":["C'est précisément le rôle démocratique des tribunaux et des lois.","Des garde-fous indépendants du pouvoir politique du moment."]},{"point":4,"male_lines":["Les lois sont écrites par des humains faillibles, sujets à l'idéologie.","Aujourd'hui c'est votre opinion qu'on censure, demain la mienne."],"female_lines":["Il y a des consensus universels sur l'incitation à la haine.","Nier l'Holocauste ou appeler au meurtre ne sont pas des opinions légitimes."]},{"point":5,"male_lines":["Mais définir la haine devient de plus en plus subjectif.","On qualifie désormais de haineux tout désaccord politique."],"female_lines":["Il y a une différence entre désaccord politique et déshumanisation.","Attaquer des groupes entiers sur leur identité n'est pas un débat."]},{"point":6,"male_lines":["Les réseaux sociaux censurent déjà trop, créant des bulles idéologiques.","Nous n'entendons plus que ce qui nous conforte."],"female_lines":["Les plateformes privées ne sont pas l'État, elles ont le droit de modérer.","Mais l'État doit encadrer cette modération pour protéger les minorités."]},{"point":7,"male_lines":["Quand l'État intervient, c'est la porte ouverte à l'autoritarisme.","Même avec les meilleures intentions."],"female_lines":["Sans intervention de l'État, c'est la loi du plus fort qui prévaut.","Les minorités sont livrées aux foules haineuses."]},{"point":8,"male_lines":["La meilleure réponse au discours haineux est plus de discours, pas moins.","La liberté d'expression inclut la liberté de réfuter."],"female_lines":["Théoriquement oui, mais pratiquement les mensonges répétés deviennent des vérités.","La parole démocratique doit être régulée pour rester saine."]},{"point":9,"male_lines":["Nous ne trouverons pas d'accord, nous partons de principes incompatibles.","Moi je privilégie la liberté, vous la sécurité."],"female_lines":["Ce n'est pas aussi simple, la liberté des uns s'arrête où commence celle des autres.","Et la liberté de vivre sans peur est fondamentale."]},{"point":10,"male_lines":["Vigilance éternelle est le prix de la liberté.","Même contre les dérives bien intentionnées."],"female_lines":["Et justice éternelle est le prix d'une société décente.","Même si cela demande des limites à la liberté absolue."]}]},{"id":39,"section":"H","theme":"The future of work","question":"Quelle vision de l'avenir du travail défend l'homme ?","options":[{"id":"A","text":"La semaine de quatre jours obligatoire","image_prompt":null},{"id":"B","text":"Le revenu universel inconditionnel","image_prompt":null},{"id":"C","text":"L'adaptation continue et la formation permanente","image_prompt":null},{"id":"D","text":"Le retour à l'artisanat local","image_prompt":null}],"correct":2,"transcript_fr":"Homme: Le travail tel qu'on le connaît disparaît, il faut s'adapter constamment. Femme: C'est angoissant pour les travailleurs. Homme: La formation permanente sera la norme. Femme: Tout le monde n'a pas les capacités d'apprendre sans cesse. Homme: Il faudra développer l'agilité cognitive. Femme: C'est une pression énorme sur les individus.","transcript_en":"Man: Work as we know it is disappearing, we must constantly adapt. Woman: It's anxiety-inducing for workers. Man: Lifelong learning will be the norm. Woman: Not everyone has the capacity to constantly learn. Man: We will need to develop cognitive agility. Woman: It's enormous pressure on individuals.","points":[{"point":1,"male_lines":["Le travail tel que nous le connaissons disparaît rapidement.","L'automatisation et l'intelligence artificielle transforment tout."],"female_lines":["C'est une perspective angoissante pour la plupart des travailleurs.","On ne sait plus à quoi s'attendre."]},{"point":2,"male_lines":["La seule réponse est l'adaptation continue et la formation permanente.","Nous devrons apprendre de nouvelles compétences tous les cinq ans."],"female_lines":["Tout le monde n'a pas les capacités cognitives d'apprendre sans cesse.","Et tout le monde n'a pas le temps entre le travail et la famille."]},{"point":3,"male_lines":["Il faudra développer l'agilité cognitive, apprendre à apprendre.","Ce sera la compétence la plus précieuse du futur."],"female_lines":["C'est une pression énorme sur les individus déjà épuisés.","On demande toujours plus d'effort personnel."]},{"point":4,"male_lines":["Les entreprises devront investir massivement dans la formation.","Ce ne sera plus une option mais une nécessité de survie."],"female_lines":["Les entreprises cherchent déjà à externaliser ces coûts.","Elles préfèrent licencier et embaucher de nouvelles compétences."]},{"point":5,"male_lines":["L'État devra encadrer cela, rendre la formation obligatoire et rémunérée.","C'est un investissement collectif dans l'avenir."],"female_lines":["Ou alors on versera un revenu universel pour ceux que la machine remplace.","Pourquoi forcer les gens à se reconvertir sans cesse?"]},{"point":6,"male_lines":["Le travail donne un sens à la vie, on ne peut pas tous vivre d'allocations.","L'humain a besoin de se sentir utile."],"female_lines":["Mais à quoi bon être utile à une machine?","Si le travail devient déshumanisant, mieux vaut s'en passer."]},{"point":7,"male_lines":["Je crois en un avenir où le travail créatif et humain prime.","Où on laisse les tâches répétitives aux robots."],"female_lines":["C'est une vision optimiste mais peu réaliste pour la majorité.","La plupart des emplois créatifs sont aussi menacés par l'IA."]},{"point":8,"male_lines":["Nous devrons redéfinir ce qui a de la valeur, pas seulement économique.","Le care, l'art, l'accompagnement seront essentiels."],"female_lines":["Ces secteurs sont justement les moins valorisés financièrement.","Il y a un décalage entre discours et réalité."]},{"point":9,"male_lines":["La transition sera difficile mais nécessaire.","Nous n'avons pas le choix, la technologie avance."],"female_lines":["Nous avons toujours le choix de la direction que nous prenons.","Technologie ne rime pas avec fatalité."]},{"point":10,"male_lines":["Je reste optimiste, l'humain s'adapte depuis des millénaires.","Nous trouverons notre place dans ce nouveau monde."],"female_lines":["J'espère que vous avez raison, mais je crains pour les plus vulnérables.","L'adaptation n'est pas égale pour tous."]}]},{"id":40,"section":"H","theme":"Cultural identity in globalization","question":"Quelle est la position de la femme sur la protection culturelle ?","options":[{"id":"A","text":"Elle est pour une protection stricte contre l'étranger","image_prompt":null},{"id":"B","text":"Elle préconise un échange culturel ouvert","image_prompt":null},{"id":"C","text":"Elle défend une identité vivante et évolutive","image_prompt":null},{"id":"D","text":"Elle rejette toute forme de culture commerciale","image_prompt":null}],"correct":2,"transcript_fr":"Homme: La mondialisation érode nos cultures locales, il faut protéger nos frontières culturelles. Femme: Mais une culture qui se ferme meurt. Homme: Sinon nous serons noyés sous la culture américaine. Femme: Il faut créer une identité vivante, évolutive, ouverte. Homme: C'est un risque. Femme: C'est une nécessité, la pureté culturelle n'existe pas.","transcript_en":"Man: Globalization erodes our local cultures, we must protect our cultural borders. Woman: But a culture that closes itself dies. Man: Otherwise we will be drowned by American culture. Woman: We must create a living, evolving, open identity. Man: It's a risk. Woman: It's a necessity, cultural purity doesn't exist.","points":[{"point":1,"male_lines":["La mondialisation érode nos cultures locales de façon alarmante.","Nous devons protéger nos frontières culturelles contre l'uniformisation."],"female_lines":["Mais une culture qui se ferme sur elle-même finit par s'appauvrir et mourir.","L'ouverture est le moteur de la vitalité culturelle."]},{"point":2,"male_lines":["Si nous ne protégeons pas notre culture québécoise, nous serons noyés.","Sous la vague de la culture américaine dominante."],"female_lines":["Il ne s'agit pas de se noyer mais de nager dans les courants.","De créer une identité vivante, évolutive, ouverte au monde."]},{"point":3,"male_lines":["C'est un risque énorme, nous pourrions perdre notre âme.","Notre langue, nos traditions, notre façon de vivre."],"female_lines":["C'est une nécessité vitale, la pureté culturelle n'existe pas.","Toute culture est un mélange constant d'influences."]},{"point":4,"male_lines":["Mais il y a une différence entre enrichissement et colonisation culturelle.","Netflix et Hollywood ne sont pas un échange équitable."],"female_lines":["C'est pourquoi nous devons produire notre propre contenu de qualité.","Pas nous isoler, mais rayonner avec notre propre voix."]},{"point":5,"male_lines":["Les jeunes parlent déjà plus anglais que français, c'est inquiétant.","Ils consomment exclusivement du contenu étranger."],"female_lines":["Ils créent aussi un français nouveau, hybride, créatif.","C'est l'évolution naturelle d'une langue vivante."]},{"point":6,"male_lines":["Nous devons imposer des quotas, protéger nos créateurs.","Subventionner massivement la culture locale."],"female_lines":["Soutenir oui, mais pas protéger au point d'étouffer.","Nos créateurs doivent être assez bons pour rayonner naturellement."]},{"point":7,"male_lines":["L'identité québécoise est fragile, elle a besoin de remparts.","Historiquement, nous avons failli disparaître."],"female_lines":["Elle est résiliente parce qu'elle s'est constamment réinventée.","Ce n'est pas la fermeture qui nous a sauvés, mais l'adaptation."]},{"point":8,"male_lines":["Je crains que l'ouverture ne soit un luxe que les cultures dominantes peuvent s'offrir.","Nous sommes minoritaires."],"female_lines":["Même minoritaires, nous avons une voix unique à partager.","Le monde a besoin de notre perspective différente."]},{"point":9,"male_lines":["Le débat reste ouvert entre protectionnisme et ouverture.","Trouver l'équilibre est difficile."],"female_lines":["L'équilibre est dans la confiance en notre capacité à créer.","Pas dans la peur de l'autre."]},{"point":10,"male_lines":["Nous verrons ce que sera le Québec dans cinquante ans.","J'espère que nous aurons su préserver l'essentiel."],"female_lines":["Je suis sûre que nous serons différents mais toujours vivants.","Et c'est cela qui compte vraiment."]}]}]`);export{e as default};
